    def _record_hit(self, mem_hit: bool) -> None:
        with self._lock:
            self._stats["hits"] += 1
            self._stats["mem_hits" if mem_hit else "disk_hits"] += 1

        if settings.usage_tracker is not None:
            settings.usage_tracker.add_cache_hit(mem_hit)

    def _record_miss(self) -> None:
        with self._lock:
            self._stats["misses"] += 1

        if settings.usage_tracker is not None:
            settings.usage_tracker.add_cache_miss()

    def stats(self) -> Dict[str, int]:
        """Return the current global cache statistics (hits, mem_hits, disk_hits, misses)."""
        with self._lock:
            return dict(self._stats)

    def reset_stats(self) -> None:
        """Reset the global cache statistics counters to zero."""
        with self._lock:
            self._stats = Counter(hits=0, mem_hits=0, disk_hits=0, misses=0)

    def put(
